            override fun upgrade(preferences: SharedPreferences) {
                preferences.edit { remove("scrolling_buttons") }
            }
        }

        internal class MigrateRedundantAnswerCommands : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                // Migrate bindings from FLIP_OR_ANSWER_RECOMMENDED to FLIP_OR_ANSWER_EASE3
                migrateBindings(preferences, "binding_FLIP_OR_ANSWER_RECOMMENDED", ViewerCommand.FLIP_OR_ANSWER_EASE3)

                // Migrate bindings from FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED to FLIP_OR_ANSWER_EASE4  
                migrateBindings(preferences, "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED", ViewerCommand.FLIP_OR_ANSWER_EASE4)
            }

            private fun migrateBindings(preferences: SharedPreferences, oldPreferenceKey: String, newCommand: ViewerCommand) {
                val oldBindings = preferences.getString(oldPreferenceKey, null)
                if (oldBindings != null) {
                    Timber.i("Migrating bindings from '$oldPreferenceKey' to '${newCommand.preferenceKey}'")

                    // Parse old bindings
                    val bindings = MappableBinding.fromPreferenceString(oldBindings)

                    // Add each binding to the new command
                    bindings.forEach { binding ->
                        newCommand.addBindingAtEnd(preferences, binding)
                    }

                    // Remove the old preference
                    preferences.edit { remove(oldPreferenceKey) }
                }
            }
        }"}

